const re = /\bhttps?:\/\/(?:www\.|m\.)?(?:facebook|fb)\.com\/[^\s"'<>]+/gi;
const matches = rawData.match(re) || [];

if (matches.length === 0) {
  return [];
}

const uniqueCleanLinks = [...new Set(
  matches
    .map(link => link.replace(/[.,;:!)\]>’"']+$/, ""))
    .filter(url => !url.startsWith("https://www.facebook.com/tr?id=") && url !== "http://www.facebook.com/2008/fbml")
)];

return uniqueCleanLinks.map(link => ({
  json: {
    FB_LINK: link
  }
}));

